def most_common_word(s):
    if not s:
        return ''

    words = s.split()
    word_count = {}

    for word in words:
        lower_word = word.lower()
        word_count[lower_word] = word_count.get(lower_word, 0) + 1

    sorted_words = sorted(word_count.items(), key=lambda x: (-x[1], x[0]))

    if not sorted_words:
        return ''

    return sorted_words[0][0]
